import { configureStore } from '@reduxjs/toolkit';
import accountReducer from '../redux/accountSlice';
import shopReducer from '../redux/shopSlice'

export const store = configureStore({
	reducer:{
		account:accountReducer,
		shop:shopReducer
	}
});
